DDL:
DROP TABLE IF EXISTS DIM_COUNTRY CASCADE;
CREATE TABLE DIM_COUNTRY (
	COUNTRY_ID BIGINT PRIMARY KEY,
	COUNTRY VARCHAR(20)
);

DROP TABLE IF EXISTS DIM_STATE CASCADE;
CREATE TABLE DIM_STATE (
	STATE_ID BIGINT PRIMARY KEY,
	STATE VARCHAR(100)
);

DROP TABLE IF EXISTS DIM_STATION CASCADE;
CREATE TABLE DIM_STATION (
	STATION_ID BIGINT PRIMARY KEY,
	STATION_CODE DOUBLE PRECISION,
	STATION_NAME VARCHAR(500),
	TYPE_OF_WATER_BODY VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_TIME CASCADE;
CREATE TABLE DIM_TIME (
	YEAR INTEGER
);

DROP TABLE IF EXISTS FACT_CHEMICAL_CONTAMINANTS CASCADE;
CREATE TABLE FACT_CHEMICAL_CONTAMINANTS (
	FACT_CHEMICAL_CONTAMINANTS_ID BIGINT PRIMARY KEY,
	STATION_ID BIGINT,
	YEAR INTEGER,
	MIN_FLUORIDE_MG_PER_L DOUBLE PRECISION,
	MAX_FLUORIDE_MG_PER_L DOUBLE PRECISION,
	MIN_ARSENIC_MG_PER_L DOUBLE PRECISION,
	MAX_ARSENIC_MG_PER_L DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_NUTRIENTS CASCADE;
CREATE TABLE FACT_NUTRIENTS (
